const { Storage } = require('@google-cloud/storage');
const path = require('path');

const storage = new Storage();

// Whitelist of allowed buckets (configure based on your environment)
const ALLOWED_BUCKETS = process.env.ALLOWED_BUCKETS 
  ? process.env.ALLOWED_BUCKETS.split(',') 
  : [];

// Maximum file size to serve (100MB default)
const MAX_FILE_SIZE = parseInt(process.env.MAX_FILE_SIZE || '104857600', 10);

function sanitizePath(filePath) {
  if (!filePath) {
    return null;
  }

  // Normalize the path to prevent directory traversal
  const normalized = path.normalize(filePath).replace(/^(\.\.(\/|\\|$))+/, '');
  
  // Remove leading slashes
  const cleaned = normalized.replace(/^[\/\\]+/, '');
  
  // Reject paths that still contain directory traversal attempts
  if (cleaned.includes('..') || cleaned.startsWith('/') || cleaned.startsWith('\\')) {
    return null;
  }
  
  // Reject absolute paths
  if (path.isAbsolute(filePath)) {
    return null;
  }
  
  return cleaned;
}

function isValidBucket(bucketName) {
  if (!bucketName || typeof bucketName !== 'string') {
    return false;
  }
  
  // Check against whitelist if configured
  if (ALLOWED_BUCKETS.length > 0) {
    return ALLOWED_BUCKETS.includes(bucketName);
  }
  
  // Basic validation: bucket names must follow GCS naming rules
  const bucketRegex = /^[a-z0-9][a-z0-9._-]{1,61}[a-z0-9]$/;
  if (!bucketRegex.test(bucketName)) {
    return false;
  }
  
  // Prevent bucket names that could be malicious
  if (bucketName.includes('..') || bucketName.includes('//')) {
    return false;
  }
  
  return true;
}

exports.serveFile = async (req, res) => {
  // Set security headers
  res.set('X-Content-Type-Options', 'nosniff');
  res.set('X-Frame-Options', 'DENY');
  res.set('X-XSS-Protection', '1; mode=block');
  res.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  
  // Only allow GET requests
  if (req.method !== 'GET') {
    res.status(405).send('Method Not Allowed');
    return;
  }
  
  try {
    const bucketName = req.query.bucket;
    const filePath = req.query.path;
    
    // Validate bucket name
    if (!isValidBucket(bucketName)) {
      res.status(400).send('Invalid or unauthorized bucket name');
      return;
    }
    
    // Sanitize and validate file path
    const sanitizedPath = sanitizePath(filePath);
    if (!sanitizedPath) {
      res.status(400).send('Invalid file path');
      return;
    }
    
    // Get bucket and file references
    const bucket = storage.bucket(bucketName);
    const file = bucket.file(sanitizedPath);
    
    // Check if file exists and get metadata
    const [exists] = await file.exists();
    if (!exists) {
      res.status(404).send('File not found');
      return;
    }
    
    // Get file metadata to check size and content type
    const [metadata] = await file.getMetadata();
    
    // Validate file size
    if (metadata.size > MAX_FILE_SIZE) {
      res.status(413).send('File too large');
      return;
    }
    
    // Set appropriate content type
    const contentType = metadata.contentType || 'application/octet-stream';
    res.set('Content-Type', contentType);
    res.set('Content-Length', metadata.size);
    
    // Set Content-Disposition to prevent inline execution of potentially dangerous files
    const filename = path.basename(sanitizedPath);
    res.set('Content-Disposition', `attachment; filename="${filename}"`);
    
    // Stream the file
    const readStream = file.createReadStream();
    
    readStream.on('error', (error) => {
      console.error('Stream error:', error);
      if (!res.headersSent) {
        res.status(500).send('Error streaming file');
      }
    });
    
    readStream.pipe(res);
    
  } catch (error) {
    console.error('Error serving file:', error);
    
    if (!res.headersSent) {
      if (error.code === 403) {
        res.status(403).send('Access denied');
      } else if (error.code === 404) {
        res.status(404).send('File not found');
      } else {
        res.status(500).send('Internal server error');
      }
    }
  }
};